// =====================================================================
// M8 · Recall (compare with past self)
// =====================================================================

@immutable
class RecallSnapshot {
  const RecallSnapshot({required this.id, required this.daysAgo, this.photoUrl});

  final String id;
  final int daysAgo;
  final String? photoUrl;

  factory RecallSnapshot.fromJson(Map<String, dynamic> json) => RecallSnapshot(
        id: json['id'] as String,
        daysAgo: (json['days_ago'] as num).toInt(),
        photoUrl: json['photo_url'] as String?,
      );
}

@immutable
class RecallCompare {
  const RecallCompare({
    required this.aiSummary,
    required this.before,
    required this.now,
  });

  final String aiSummary;
  final RecallSnapshot before;
  final RecallSnapshot now;

  factory RecallCompare.fromJson(Map<String, dynamic> json) => RecallCompare(
        aiSummary: json['ai_summary'] as String,
        before: RecallSnapshot.fromJson(
          (json['before'] as Map<String, dynamic>),
        ),
        now: RecallSnapshot.fromJson(
          (json['now'] as Map<String, dynamic>),
        ),
      );
}

